package main

import (
	"net/http"
	"path/filepath"
	"os"
	"strings"
	"log"
)

const baseDir = "./uploads"

func fileHandler(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("filename")
	if filename == "" {
		http.Error(w, "Filename is required", http.StatusBadRequest)
		return
	}

	// Clean and resolve the path
	cleanPath := filepath.Clean("/" + filename)
	resolvedPath := filepath.Join(baseDir, cleanPath)

	// Ensure the resolved path is within the base directory
	if !strings.HasPrefix(resolvedPath, filepath.Clean(baseDir)+string(os.PathSeparator)) {
		http.Error(w, "Invalid file path", http.StatusForbidden)
		return
	}

	// Open the file
	file, err := os.Open(resolvedPath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	// Detect content type
	contentType := http.DetectContentType(make([]byte, 512))
	w.Header().Set("Content-Type", contentType)

	// Serve the file
	http.ServeContent(w, r, filename, file.ModTime(), file)
}

func main() {
	http.HandleFunc("/files", fileHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}